          </div>
          {columns.map((column) => {
            const meta = (column.columnDef.meta ?? {}) as DataGridColumnMeta
            const columnLabel = meta.label ?? column.id
            const inputId = `data-grid-filter-${column.id}`
            return (
              <label className="grid gap-1.5 text-sm" htmlFor={inputId} key={column.id}>
